      "primary_intervention": "9-fraction whole breast radiation with simultaneous lumpectomy boost (3420 cGy to breast, 3960 cGy to cavity)",
      "intervention_type": "radiation"
    },
    "outcomes": {
      "primary_endpoints": [
        {
          "primary_endpoint_text": "photographic cosmetic scores at 24 months",
          "primary_endpoint_category": "quality_of_life",
          "primary_endpoint_results": "68% excellent/good at 24 months; null hypothesis not rejected (one-sided 95% CI 59.1% (59.1%-100%))",
          "statistical_significance_assessment": "Not statistically significant",
          "statistical_significance_assessment_reason": "Null hypothesis was not rejected."
        }
      ],
      "secondary_endpoints": [
        "late radiation toxicity",
        "patient-reported breast satisfaction"
      ],
      "study_conclusions": "We demonstrate an effective novel 9 fraction whole breast + lumpectomy boost radiation schedule. This trial uses one of the shortest published radiation schedules for a lumpectomy boost. Although we did not meet our prespecified cosmetic endpoint, no significant cosmetic change from baseline was seen in 80% of patients. We demonstrate excellent local control, and patient-reported satisfaction with low RT-related toxicity. We hope to move this concept forward in a randomized trial against the 5-day United Kingdom (UK) Fast Forward regimen, inclusive of a simultaneous lumpectomy cavity boost.",
      "conclusions_category": "solid_findings_more_research_needed"
    }
  },
  "extraction_confidence": {
    "overall_confidence": "high",
    "missing_critical_elements": [
      "multicenter"
    ],
    "extraction_notes": "Primary endpoint mapped to quality_of_life; secondary endpoints listed as described in abstract."
  }
}

